<# Request a safe stop. BrainLive drains the inbox, then performs resumable post-stop + close-day. #>
[CmdletBinding()]
param([string]$PersonId="me",[int]$TimeoutSeconds=5400)
$ErrorActionPreference="Stop";$ProjectRoot=(Resolve-Path $PSScriptRoot).Path;$EnvPath=Join-Path $ProjectRoot ".env";$Python=Join-Path $ProjectRoot ".venv\Scripts\python.exe";$Runtime=Join-Path $ProjectRoot ".mlomega_audio_elite\runtime\brainlive_service.json";$Launcher=Join-Path $ProjectRoot ".mlomega_audio_elite\runtime\launcher-v18_8.json"
function Fail($m){throw "STOP V18.8 BLOQUÉ: $m"};function Env{Get-Content $EnvPath|%{if($_ -match '^\s*#' -or $_ -notmatch '='){return};$x=$_ -split '=',2;if($x[0].Trim()){Set-Item "Env:$($x[0].Trim())" $x[1]}};$env:MLOMEGA_PROJECT_ROOT=$ProjectRoot};function ReadJson($p){if(Test-Path $p){try{return Get-Content $p -Raw|ConvertFrom-Json}catch{}};return $null}
try{Set-Location $ProjectRoot;Env;if(!(Test-Path $Python)){Fail ".venv absent"};$s=ReadJson $Runtime;if(!$s -or !$s.service_run_id){Fail "Aucun service BrainLive actif dans le manifeste."};$launcher=ReadJson $Launcher;$packageDate=if($launcher -and $launcher.package_date){[string]$launcher.package_date}else{(Get-Date).ToString('yyyy-MM-dd')};& $Python -m mlomega_audio_elite.cli brainlive-stop-service --service-run-id $s.service_run_id --close-day|Out-Host;if($LASTEXITCODE -ne 0){Fail "La demande d'arrêt BrainLive a échoué (code $LASTEXITCODE). Aucune purge n'a été lancée."};$deadline=(Get-Date).AddSeconds($TimeoutSeconds);$last=$null;while((Get-Date)-lt $deadline){$out=& $Python -m mlomega_audio_elite.cli brainlive-close-day-status --person-id $PersonId --package-date $packageDate 2>$null;if($LASTEXITCODE -ne 0){Start-Sleep 5;continue};$last=$out -join "`n";try{$j=$last|ConvertFrom-Json;if($j.status -eq 'completed'){Write-Host "CLOTURE V18.8 TERMINÉE" -ForegroundColor Green;exit 0};if($j.status -in @('retryable_error','failed','blocked')){Write-Host "Clôture retenue en état $($j.status). Les sources sont conservées. Lance RESUME_MLOMEGA_V18_8.ps1." -ForegroundColor Yellow;exit 2}}catch{};Start-Sleep 5};Fail "Délai de clôture dépassé. Les checkpoints sont conservés; lance RESUME_MLOMEGA_V18_8.ps1."}catch{Write-Host $_.Exception.Message -ForegroundColor Red;exit 1}
